sys_script_include.script:
var IncentIQIntentRouter = Class.create();

IncentIQIntentRouter.prototype = {

    initialize: function() {

        this.intentMatcher =
            new IncentIQIntentMatcher();

        this.orchestrator =
            new IncentIQOrchestrator();
    },

    getResponse: function(query, userId) {

        gs.info(
            "INCENTIQ_ROUTER :: START"
        );

        gs.info(
            "INCENTIQ_ROUTER :: QUERY = " +
            query
        );

        gs.info(
            "INCENTIQ_ROUTER :: USER = " +
            userId
        );

        try {

            query = (query || "")
                .toString()
                .trim();

            if (!query) {

                return "Please enter your question.";
            }

            var intent =
                this.intentMatcher
                .classifyIntentUsingAI(
                    query
                );

            gs.info(
                "INCENTIQ_ROUTER :: DETECTED INTENT = " +
                intent
            );

            if (
                !intent ||
                intent == "unknown"
            ) {

                return this.intentMatcher
                    .storeUnknownQuestion(
                        query,
                        userId,
                        "unknown"
                    );
            }

            return this.orchestrator
                .execute(
                    intent,
                    userId,
                    query
                );

        } catch (ex) {

            gs.error(
                "INCENTIQ_ROUTER :: ERROR = " +
                ex.message
            );

            return "Unable to process your request at this time.";
        }
    },

    type: "IncentIQIntentRouter"
};
